CREATE TABLE IF NOT EXISTS xvchat_calls (id TEXT PRIMARY KEY, caller_id TEXT NOT NULL, receiver_id TEXT NOT NULL, call_type TEXT NOT NULL DEFAULT 'audio', status TEXT NOT NULL DEFAULT 'pending', started_at TIMESTAMPTZ, ended_at TIMESTAMPTZ, duration INTEGER, created_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE IF NOT EXISTS xvchat_contacts (id TEXT PRIMARY KEY, user_id TEXT NOT NULL, contact_id TEXT NOT NULL, created_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(user_id, contact_id)); CREATE INDEX IF NOT EXISTS idx_xvchat_messages_chat ON xvchat_messages(chat_id); CREATE INDEX IF NOT EXISTS idx_xvchat_messages_created ON xvchat_messages(created_at DESC);